import React, { useState, useEffect } from 'react';

const API = 'http://localhost:5000/api';

const DoctorDashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [queueData, setQueueData] = useState([]);
  const [allQueue, setAllQueue] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [stats, setStats] = useState({ patientsInQueue: 0, todaysAppointments: 0 });
  const [loading, setLoading] = useState(true);
  const [patients, setPatients] = useState([]);
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [showPrescriptionModal, setShowPrescriptionModal] = useState(false);
  const [showLabTestModal, setShowLabTestModal] = useState(false);
  const [prescriptions, setPrescriptions] = useState([]);
  const [labTests, setLabTests] = useState([]);
  const [selectedPatientHistory, setSelectedPatientHistory] = useState(null);
  const [patientTriageHistory, setPatientTriageHistory] = useState([]);
  const [notification, setNotification] = useState(null);

  // Portfolio edit state
  const [editingPortfolio, setEditingPortfolio] = useState(false);
  const [portfolioForm, setPortfolioForm] = useState({
    firstName: user?.firstName || '',
    lastName: user?.lastName || '',
    email: user?.email || '',
    specialization: 'General Physician',
    phone: user?.phone || '',
  });

  const [prescriptionForm, setPrescriptionForm] = useState({
    medication_name: '', dosage: '', frequency: '', duration: '', instructions: ''
  });

  const [labTestForm, setLabTestForm] = useState({ test_type: 'hematology', test_name: '', notes: '' });

  const commonLabTests = {
    hematology: ['Complete Blood Count (CBC)', 'Blood Typing', 'ESR'],
    chemistry: ['Comprehensive Metabolic Panel', 'Liver Function Tests', 'Kidney Function Tests', 'Lipid Profile', 'Blood Glucose', 'HbA1c'],
    microbiology: ['Blood Culture', 'Urine Culture', 'Wound Culture', 'Stool Culture'],
    immunology: ['HIV Test', 'Hepatitis B Surface Antigen', 'Hepatitis C Antibody', 'VDRL/RPR'],
    urinalysis: ['Urine Analysis', 'Urine Pregnancy Test'],
    parasitology: ['Stool Ova & Parasites', 'Blood Parasite Smear']
  };

  const showNotification = (msg, type = 'success') => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 3500);
  };

  const token = () => localStorage.getItem('token');
  const headers = () => ({ 'Content-Type': 'application/json', 'Authorization': `Bearer ${token()}` });

  useEffect(() => {
    fetchDashboardData();
  }, []);

  useEffect(() => {
    if (activeTab === 'pharmacy') fetchPrescriptions();
    else if (activeTab === 'laboratory') fetchLabTests();
    else if (activeTab === 'queue') fetchAllQueue();
  }, [activeTab]);

  const fetchDashboardData = async () => {
    try {
      const [queueRes, patientsRes, apptRes] = await Promise.all([
        fetch(`${API}/queue`, { headers: headers() }),
        fetch(`${API}/patients`, { headers: headers() }),
        fetch(`${API}/appointments/today`, { headers: headers() }),
      ]);

      if (queueRes.ok) {
        const data = await queueRes.json();
        const waiting = data.filter(q => q.status === 'waiting');
        setQueueData(waiting.slice(0, 5));
        setStats(prev => ({ ...prev, patientsInQueue: waiting.length }));
      }
      if (patientsRes.ok) {
        const data = await patientsRes.json();
        setPatients(data);
      }
      if (apptRes.ok) {
        const data = await apptRes.json();
        setAppointments(data);
        setStats(prev => ({ ...prev, todaysAppointments: data.length }));
      }
    } catch (err) {
      console.error('Error fetching dashboard data:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchAllQueue = async () => {
    try {
      const res = await fetch(`${API}/queue`, { headers: headers() });
      if (res.ok) {
        const data = await res.json();
        setAllQueue(data);
      }
    } catch (err) {
      console.error('Error fetching queue:', err);
    }
  };

  const fetchPrescriptions = async () => {
    try {
      const res = await fetch(`${API}/prescriptions`, { headers: headers() });
      if (res.ok) setPrescriptions(await res.json());
    } catch (err) { console.error(err); }
  };

  const fetchLabTests = async () => {
    try {
      const res = await fetch(`${API}/lab-tests`, { headers: headers() });
      if (res.ok) setLabTests(await res.json());
    } catch (err) { console.error(err); }
  };

  const fetchPatientTriageHistory = async (patientId) => {
    try {
      const res = await fetch(`${API}/triage/patient/${patientId}`, { headers: headers() });
      if (res.ok) setPatientTriageHistory(await res.json());
    } catch (err) { console.error(err); }
  };

  const handleCallNext = async () => {
    try {
      const res = await fetch(`${API}/queue/call-next`, {
        method: 'POST',
        headers: headers(),
        body: JSON.stringify({ doctor_id: user?.id, room_number: 'Room 101' })
      });
      if (res.ok) {
        const data = await res.json();
        showNotification(`Called: ${data.patient?.patient_first_name} ${data.patient?.patient_last_name}`);
        fetchDashboardData();
        if (activeTab === 'queue') fetchAllQueue();
      } else {
        const err = await res.json();
        showNotification(err.message || 'No patients in queue', 'error');
      }
    } catch (err) {
      showNotification('Failed to call next patient', 'error');
    }
  };

  const handleCompleteConsultation = async (queueId) => {
    try {
      const res = await fetch(`${API}/queue/${queueId}`, {
        method: 'PUT',
        headers: headers(),
        body: JSON.stringify({ status: 'completed' })
      });
      if (res.ok) {
        showNotification('Consultation marked as completed');
        fetchAllQueue();
        fetchDashboardData();
      }
    } catch (err) {
      showNotification('Failed to update status', 'error');
    }
  };

  const handleCreatePrescription = async (e) => {
    e.preventDefault();
    if (!selectedPatient) { showNotification('Please select a patient', 'error'); return; }
    try {
      const res = await fetch(`${API}/prescriptions`, {
        method: 'POST',
        headers: headers(),
        body: JSON.stringify({ patient_id: selectedPatient.id, ...prescriptionForm })
      });
      if (res.ok) {
        showNotification('Prescription created successfully');
        setShowPrescriptionModal(false);
        setPrescriptionForm({ medication_name: '', dosage: '', frequency: '', duration: '', instructions: '' });
        setSelectedPatient(null);
        fetchPrescriptions();
      } else {
        const err = await res.json();
        showNotification(err.message || 'Failed to create prescription', 'error');
      }
    } catch (err) {
      showNotification('Failed to create prescription', 'error');
    }
  };

  const handleCreateLabTest = async (e) => {
    e.preventDefault();
    if (!selectedPatient) { showNotification('Please select a patient', 'error'); return; }
    try {
      const res = await fetch(`${API}/lab-tests`, {
        method: 'POST',
        headers: headers(),
        body: JSON.stringify({ patient_id: selectedPatient.id, ...labTestForm })
      });
      if (res.ok) {
        showNotification('Lab test ordered successfully');
        setShowLabTestModal(false);
        setLabTestForm({ test_type: 'hematology', test_name: '', notes: '' });
        setSelectedPatient(null);
        fetchLabTests();
      } else {
        const err = await res.json();
        showNotification(err.message || 'Failed to order lab test', 'error');
      }
    } catch (err) {
      showNotification('Failed to order lab test', 'error');
    }
  };

  const handleSavePortfolio = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API}/users/${user?.id}`, {
        method: 'PUT',
        headers: headers(),
        body: JSON.stringify({
          firstName: portfolioForm.firstName,
          lastName: portfolioForm.lastName,
          phone: portfolioForm.phone,
        })
      });
      if (res.ok) {
        showNotification('Profile updated successfully');
        setEditingPortfolio(false);
      } else {
        const err = await res.json();
        showNotification(err.message || 'Failed to update profile', 'error');
      }
    } catch (err) {
      showNotification('Failed to update profile', 'error');
    }
  };

  const statusBadge = (status) => {
    const map = {
      waiting: 'bg-yellow-100 text-yellow-800',
      in_consultation: 'bg-blue-100 text-blue-800',
      completed: 'bg-green-100 text-green-800',
      cancelled: 'bg-red-100 text-red-800',
      scheduled: 'bg-purple-100 text-purple-800',
      confirmed: 'bg-teal-100 text-teal-800',
      in_progress: 'bg-blue-100 text-blue-800',
    };
    return map[status] || 'bg-gray-100 text-gray-800';
  };

  const navItems = [
    { key: 'dashboard', icon: '📊', label: 'Dashboard' },
    { key: 'queue', icon: '📋', label: 'Appointment/Queue' },
    { key: 'laboratory', icon: '🔬', label: 'Laboratory' },
    { key: 'pharmacy', icon: '💊', label: 'Pharmacy' },
    { key: 'patientHistory', icon: '🗂️', label: 'Patient History' },
    { key: 'portfolio', icon: '👤', label: 'Portfolio' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Notification */}
      {notification && (
        <div className={`fixed top-4 right-4 z-50 px-6 py-3 rounded-lg shadow-lg text-white font-semibold transition-all ${
          notification.type === 'error' ? 'bg-red-500' : 'bg-green-500'
        }`}>
          {notification.msg}
        </div>
      )}

      {/* Sidebar */}
      <div className="w-64 bg-slate-800 text-white min-h-screen flex flex-col">
        <div className="p-6">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-gradient-to-br from-green-400 to-blue-500 rounded-lg flex items-center justify-center">
              <span className="text-white text-xl">🏥</span>
            </div>
            <div>
              <h1 className="text-xl font-bold">Patient</h1>
              <h2 className="text-lg font-semibold">Management</h2>
            </div>
          </div>
        </div>
        <nav className="mt-4 flex-1">
          {navItems.map(item => (
            <button
              key={item.key}
              onClick={() => setActiveTab(item.key)}
              className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
                activeTab === item.key ? 'bg-blue-600 border-l-4 border-blue-400' : 'hover:bg-slate-700'
              }`}
            >
              <span className="mr-3">{item.icon}</span>
              {item.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <header className="bg-white shadow-sm">
          <div className="px-8 py-4 flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold text-gray-900">Doctor Dashboard</h2>
              <p className="text-sm text-gray-500">Last updated: {new Date().toLocaleTimeString()}</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="text-right">
                <p className="text-sm font-medium text-gray-900">Dr. {user?.firstName} {user?.lastName}</p>
                <p className="text-xs text-gray-500">General Physician</p>
              </div>
              <div className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white font-bold text-lg">
                {user?.firstName?.charAt(0)}{user?.lastName?.charAt(0)}
              </div>
              <button onClick={onLogout} className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors">
                Logout
              </button>
            </div>
          </div>
        </header>

        <main className="flex-1 p-8 overflow-auto">

          {/* ── DASHBOARD TAB ── */}
          {activeTab === 'dashboard' && (
            <div>
              <div className="bg-gradient-to-r from-blue-400 to-green-500 rounded-xl shadow-lg p-8 mb-8 text-white">
                <div className="flex items-center justify-between">
                  <div>
                    <h1 className="text-3xl font-bold mb-2">Welcome, Dr. {user?.firstName}!</h1>
                    <p className="text-lg opacity-90">Have a nice time and try to care your patients kindly!!!</p>
                  </div>
                  <span className="text-6xl">👨‍⚕️</span>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                <div className="bg-white rounded-xl shadow-lg p-6 flex items-center justify-between">
                  <div>
                    <p className="text-gray-600 mb-1">Patients in Queue</p>
                    <p className="text-4xl font-bold text-gray-900">{stats.patientsInQueue}</p>
                  </div>
                  <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center text-3xl">👥</div>
                </div>
                <div className="bg-white rounded-xl shadow-lg p-6 flex items-center justify-between">
                  <div>
                    <p className="text-gray-600 mb-1">Today's Appointments</p>
                    <p className="text-4xl font-bold text-gray-900">{stats.todaysAppointments}</p>
                  </div>
                  <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center text-3xl">✅</div>
                </div>
              </div>

              <div className="bg-white rounded-xl shadow-lg p-6">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-xl font-bold text-gray-900">Current Patient Queue</h3>
                  <button onClick={handleCallNext} className="px-6 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold">
                    Call Next Patient
                  </button>
                </div>
                {loading ? (
                  <div className="text-center py-8">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mx-auto"></div>
                    <p className="text-gray-600 mt-4">Loading queue...</p>
                  </div>
                ) : queueData.length === 0 ? (
                  <div className="text-center py-12">
                    <span className="text-6xl mb-4 block">📋</span>
                    <p className="text-gray-600 text-lg">No patients in queue</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {queueData.map((patient, index) => (
                      <div key={patient.id} className={`flex items-center justify-between p-4 rounded-lg border-l-4 ${index === 0 ? 'bg-blue-50 border-blue-500' : 'bg-gray-50 border-gray-300'}`}>
                        <div className="flex items-center space-x-4">
                          <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-bold ${index === 0 ? 'bg-blue-500' : 'bg-gray-400'}`}>
                            {patient.queue_number}
                          </div>
                          <div>
                            <p className="font-semibold text-gray-900">{patient.patient_id}</p>
                            <p className="text-sm text-gray-600">{patient.patient_first_name} {patient.patient_last_name}</p>
                          </div>
                        </div>
                        {index === 0 && <span className="px-4 py-2 bg-blue-500 text-white rounded-full text-sm font-semibold">Next</span>}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* ── APPOINTMENT/QUEUE TAB ── */}
          {activeTab === 'queue' && (
            <div className="space-y-6">
              {/* Today's Appointments */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-2xl font-bold text-gray-900">Today's Appointments</h3>
                  <button onClick={fetchDashboardData} className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors text-sm font-medium">
                    🔄 Refresh
                  </button>
                </div>
                {appointments.length === 0 ? (
                  <div className="text-center py-10">
                    <span className="text-5xl block mb-3">📅</span>
                    <p className="text-gray-500">No appointments scheduled for today</p>
                  </div>
                ) : (
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Time</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Type</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Notes</th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {appointments.map(appt => (
                          <tr key={appt.id} className="hover:bg-gray-50">
                            <td className="px-4 py-3 text-sm font-medium text-gray-900">{appt.appointment_time}</td>
                            <td className="px-4 py-3">
                              <p className="text-sm font-medium text-gray-900">{appt.patient_first_name} {appt.patient_last_name}</p>
                              <p className="text-xs text-gray-500">{appt.patient_id}</p>
                            </td>
                            <td className="px-4 py-3">
                              <span className="px-2 py-1 text-xs font-semibold rounded-full bg-purple-100 text-purple-800 capitalize">{appt.appointment_type}</span>
                            </td>
                            <td className="px-4 py-3">
                              <span className={`px-2 py-1 text-xs font-semibold rounded-full capitalize ${statusBadge(appt.status)}`}>{appt.status}</span>
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-500">{appt.notes || '—'}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>

              {/* Full Queue */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-2xl font-bold text-gray-900">Patient Queue</h3>
                  <button onClick={handleCallNext} className="px-6 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold">
                    Call Next Patient
                  </button>
                </div>
                {allQueue.length === 0 ? (
                  <div className="text-center py-10">
                    <span className="text-5xl block mb-3">🏥</span>
                    <p className="text-gray-500">Queue is empty</p>
                  </div>
                ) : (
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">#</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Phone</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Room</th>
                          <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Action</th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {allQueue.map(q => (
                          <tr key={q.id} className="hover:bg-gray-50">
                            <td className="px-4 py-3">
                              <span className="w-8 h-8 bg-blue-500 text-white rounded-full flex items-center justify-center text-sm font-bold">{q.queue_number}</span>
                            </td>
                            <td className="px-4 py-3">
                              <p className="text-sm font-medium text-gray-900">{q.patient_first_name} {q.patient_last_name}</p>
                              <p className="text-xs text-gray-500">{q.patient_id}</p>
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">{q.patient_phone || '—'}</td>
                            <td className="px-4 py-3">
                              <span className={`px-2 py-1 text-xs font-semibold rounded-full capitalize ${statusBadge(q.status)}`}>{q.status?.replace('_', ' ')}</span>
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">{q.assigned_room || '—'}</td>
                            <td className="px-4 py-3">
                              {q.status === 'in_consultation' && (
                                <button
                                  onClick={() => handleCompleteConsultation(q.id)}
                                  className="px-3 py-1 bg-green-500 text-white text-xs rounded-lg hover:bg-green-600 transition-colors font-semibold"
                                >
                                  Complete
                                </button>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* ── LABORATORY TAB ── */}
          {activeTab === 'laboratory' && (
            <div className="bg-white rounded-xl shadow-lg p-6">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-900">Laboratory Orders</h3>
                <button onClick={() => setShowLabTestModal(true)} className="px-6 py-3 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold">
                  + Order Lab Test
                </button>
              </div>
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Test Type</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Test Name</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Requested</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {labTests.length === 0 ? (
                      <tr><td colSpan="5" className="px-6 py-8 text-center text-gray-500">No lab tests ordered yet</td></tr>
                    ) : labTests.map(test => (
                      <tr key={test.id} className="hover:bg-gray-50">
                        <td className="px-6 py-4">
                          <p className="text-sm font-medium text-gray-900">{test.patient_first_name} {test.patient_last_name}</p>
                          <p className="text-xs text-gray-500">{test.patient_id}</p>
                        </td>
                        <td className="px-6 py-4"><span className="px-3 py-1 text-xs font-semibold rounded-full bg-blue-100 text-blue-800 capitalize">{test.test_type}</span></td>
                        <td className="px-6 py-4 text-sm text-gray-900">{test.test_name}</td>
                        <td className="px-6 py-4"><span className={`px-3 py-1 text-xs font-semibold rounded-full capitalize ${statusBadge(test.status)}`}>{test.status}</span></td>
                        <td className="px-6 py-4 text-sm text-gray-500">{new Date(test.requested_at).toLocaleDateString()}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── PHARMACY TAB ── */}
          {activeTab === 'pharmacy' && (
            <div className="bg-white rounded-xl shadow-lg p-6">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-900">Prescriptions</h3>
                <button onClick={() => setShowPrescriptionModal(true)} className="px-6 py-3 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors font-semibold">
                  + Create Prescription
                </button>
              </div>
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Medication</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Dosage</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Frequency</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Issued</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {prescriptions.length === 0 ? (
                      <tr><td colSpan="6" className="px-6 py-8 text-center text-gray-500">No prescriptions created yet</td></tr>
                    ) : prescriptions.map(rx => (
                      <tr key={rx.id} className="hover:bg-gray-50">
                        <td className="px-6 py-4">
                          <p className="text-sm font-medium text-gray-900">{rx.patient_first_name} {rx.patient_last_name}</p>
                          <p className="text-xs text-gray-500">{rx.patient_id}</p>
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-900">{rx.medication_name}</td>
                        <td className="px-6 py-4 text-sm text-gray-500">{rx.dosage}</td>
                        <td className="px-6 py-4 text-sm text-gray-500">{rx.frequency}</td>
                        <td className="px-6 py-4"><span className={`px-3 py-1 text-xs font-semibold rounded-full capitalize ${statusBadge(rx.status)}`}>{rx.status}</span></td>
                        <td className="px-6 py-4 text-sm text-gray-500">{new Date(rx.issued_at).toLocaleDateString()}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── PATIENT HISTORY TAB ── */}
          {activeTab === 'patientHistory' && (
            <PatientHistoryTab
              patients={patients}
              user={user}
              headers={headers}
              showNotification={showNotification}
              statusBadge={statusBadge}
            />
          )}

          {/* ── PORTFOLIO TAB ── */}
          {activeTab === 'portfolio' && (
            <div className="bg-white rounded-xl shadow-lg p-8 max-w-2xl">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-900">My Portfolio</h3>
                {!editingPortfolio && (
                  <button
                    onClick={() => setEditingPortfolio(true)}
                    className="px-5 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold"
                  >
                    ✏️ Edit Profile
                  </button>
                )}
              </div>

              {editingPortfolio ? (
                <form onSubmit={handleSavePortfolio} className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">First Name</label>
                      <input
                        type="text"
                        value={portfolioForm.firstName}
                        onChange={e => setPortfolioForm({ ...portfolioForm, firstName: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                        required
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Last Name</label>
                      <input
                        type="text"
                        value={portfolioForm.lastName}
                        onChange={e => setPortfolioForm({ ...portfolioForm, lastName: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                        required
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                    <input
                      type="email"
                      value={portfolioForm.email}
                      onChange={e => setPortfolioForm({ ...portfolioForm, email: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                    <input
                      type="text"
                      value={portfolioForm.phone}
                      onChange={e => setPortfolioForm({ ...portfolioForm, phone: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Specialization</label>
                    <input
                      type="text"
                      value={portfolioForm.specialization}
                      onChange={e => setPortfolioForm({ ...portfolioForm, specialization: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                  <div className="flex space-x-4 pt-2">
                    <button type="submit" className="flex-1 px-6 py-3 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold">
                      Save Changes
                    </button>
                    <button type="button" onClick={() => setEditingPortfolio(false)} className="flex-1 px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors font-semibold">
                      Cancel
                    </button>
                  </div>
                </form>
              ) : (
                <div className="space-y-5">
                  <div className="flex items-center space-x-4 mb-6">
                    <div className="w-20 h-20 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white font-bold text-3xl">
                      {user?.firstName?.charAt(0)}{user?.lastName?.charAt(0)}
                    </div>
                    <div>
                      <p className="text-2xl font-bold text-gray-900">Dr. {user?.firstName} {user?.lastName}</p>
                      <p className="text-gray-500">{portfolioForm.specialization}</p>
                    </div>
                  </div>
                  {[
                    { label: 'Email', value: user?.email },
                    { label: 'Phone', value: user?.phone || portfolioForm.phone || 'Not set' },
                    { label: 'Role', value: 'Doctor' },
                    { label: 'Specialization', value: portfolioForm.specialization },
                  ].map(({ label, value }) => (
                    <div key={label} className="flex items-center border-b border-gray-100 pb-4">
                      <span className="w-36 text-sm font-medium text-gray-500">{label}</span>
                      <span className="text-gray-900">{value}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </main>
      </div>

      {/* ── PRESCRIPTION MODAL ── */}
      {showPrescriptionModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-bold text-gray-900 mb-6">Create Prescription</h3>
            <form onSubmit={handleCreatePrescription} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Select Patient *</label>
                <select
                  value={selectedPatient?.id || ''}
                  onChange={e => setSelectedPatient(patients.find(p => p.id === e.target.value) || null)}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500"
                  required
                >
                  <option value="">Choose a patient...</option>
                  {patients.map(p => <option key={p.id} value={p.id}>{p.patient_id} - {p.first_name} {p.last_name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Medication Name *</label>
                <input type="text" value={prescriptionForm.medication_name} onChange={e => setPrescriptionForm({...prescriptionForm, medication_name: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500" placeholder="e.g., Paracetamol" required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Dosage *</label>
                  <input type="text" value={prescriptionForm.dosage} onChange={e => setPrescriptionForm({...prescriptionForm, dosage: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500" placeholder="e.g., 500mg" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Frequency *</label>
                  <input type="text" value={prescriptionForm.frequency} onChange={e => setPrescriptionForm({...prescriptionForm, frequency: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500" placeholder="e.g., 3x daily" required />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Duration *</label>
                <input type="text" value={prescriptionForm.duration} onChange={e => setPrescriptionForm({...prescriptionForm, duration: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500" placeholder="e.g., 5 days" required />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Instructions</label>
                <textarea value={prescriptionForm.instructions} onChange={e => setPrescriptionForm({...prescriptionForm, instructions: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500" rows="3" placeholder="Additional instructions..." />
              </div>
              <div className="flex space-x-4 pt-2">
                <button type="submit" className="flex-1 px-6 py-3 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors font-semibold">Create Prescription</button>
                <button type="button" onClick={() => { setShowPrescriptionModal(false); setSelectedPatient(null); setPrescriptionForm({ medication_name: '', dosage: '', frequency: '', duration: '', instructions: '' }); }} className="flex-1 px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors font-semibold">Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ── LAB TEST MODAL ── */}
      {showLabTestModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-bold text-gray-900 mb-6">Order Lab Test</h3>
            <form onSubmit={handleCreateLabTest} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Select Patient *</label>
                <select
                  value={selectedPatient?.id || ''}
                  onChange={e => setSelectedPatient(patients.find(p => p.id === e.target.value) || null)}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                  required
                >
                  <option value="">Choose a patient...</option>
                  {patients.map(p => <option key={p.id} value={p.id}>{p.patient_id} - {p.first_name} {p.last_name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Test Type *</label>
                <select value={labTestForm.test_type} onChange={e => setLabTestForm({...labTestForm, test_type: e.target.value, test_name: ''})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" required>
                  {Object.keys(commonLabTests).map(t => <option key={t} value={t} className="capitalize">{t.charAt(0).toUpperCase() + t.slice(1)}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Test Name *</label>
                <select value={labTestForm.test_name} onChange={e => setLabTestForm({...labTestForm, test_name: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" required>
                  <option value="">Choose a test...</option>
                  {commonLabTests[labTestForm.test_type]?.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                <textarea value={labTestForm.notes} onChange={e => setLabTestForm({...labTestForm, notes: e.target.value})} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" rows="3" placeholder="Special instructions..." />
              </div>
              <div className="flex space-x-4 pt-2">
                <button type="submit" className="flex-1 px-6 py-3 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold">Order Lab Test</button>
                <button type="button" onClick={() => { setShowLabTestModal(false); setSelectedPatient(null); setLabTestForm({ test_type: 'hematology', test_name: '', notes: '' }); }} className="flex-1 px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors font-semibold">Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DoctorDashboard;
